package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

func processa(vet []int) {
	lista := vet;

	vetAux := []int{};

	for i := 0; i < len(lista) - 1; i++ {
		vetAux = append(vetAux, lista[i] + lista[i + 1]);
	}

	if len(vetAux) >= 1 {
		processa(vetAux);
	}
	fmt.Print("[")
	fmt.Print(Join(vet, " "))
	fmt.Println("]")


}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	if !scanner.Scan() {
		return
	}
	line := scanner.Text()
	parts := strings.Fields(line)
	vet := []int{}
	for _, part := range parts {
		if value, err := strconv.Atoi(part); err == nil {
			vet = append(vet, value)
		}
	}
	processa(vet)
}

func Join[T any](v []T, sep string) string {
	if len(v) == 0 {
		return ""
	}
	s := " "
	for i, x := range v {
		if i > 0 {
			s += sep
		}
		s += fmt.Sprintf("%v", x)
	}
	s += " "
	return s
}
